import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import EditProfile from "../users/EditProfile";

export default function AdminProfile() {
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showEditProfile, setShowEditProfile] = useState(false);

  useEffect(() => {
    fetchUser();
  }, []);

  const fetchUser = async () => {
    try {
      const raw = localStorage.getItem("user");

      if (!raw) {
        setLoading(false);
        return;
      }

      const stored = JSON.parse(raw);
      const email = stored?.email;

      if (!email) {
        setLoading(false);
        return;
      }

      const res = await axios.get(
        `http://localhost:8086/user/profile?email=${email}`
      );

      setUser(res.data);
    } catch (err) {
      console.log("Profile fetch error:", err);
    } finally {
      setLoading(false);
    }
  };

  const getRoleTitle = (role) => {
    if (!role) return "User Profile";

    const r = role.toLowerCase();

    if (r === "admin") return "Admin Profile";
    if (r.includes("academic")) return "Academic Panel Profile";

    return "User Profile";
  };

  const role = user?.role?.toLowerCase() || "";

  const isAdminOrAcademic =
    role === "admin" || role.includes("academic");

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-100">
        Loading profile...
      </div>
    );
  }

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-100">
        No user found. Please login again.
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 p-8 ml-[17vw]">

      {/* HEADER */}
      <div className="mb-6">
        <h1 className="text-2xl font-bold">
          {getRoleTitle(user.role)}
        </h1>
        <p className="text-gray-500 text-sm">
          Manage account details and access
        </p>
      </div>

      <div className="grid grid-cols-3 gap-6">

        {/* LEFT CARD */}
        <div className="bg-white p-6 rounded-2xl shadow-md flex flex-col items-center">

          <img
            src={
              user.profileImage ||
              `https://ui-avatars.com/api/?name=${user.username}`
            }
            className="w-28 h-28 rounded-full border-4 border-indigo-500"
            alt="profile"
          />

          <h2 className="mt-4 font-bold text-xl">{user.name}</h2>
          <p className="text-gray-500 text-sm">{user.email}</p>

          <span className="mt-2 px-3 py-1 text-xs bg-indigo-100 text-indigo-700 rounded-full">
            {user.role}
          </span>

          <div className="w-full mt-6 space-y-3">

            {isAdminOrAcademic && (
              <button
                onClick={() => setShowEditProfile(true)}
                className="w-full bg-indigo-600 text-white py-2 rounded-lg"
              >
                Edit Profile
              </button>
            )}

            <button
              onClick={() => {
                localStorage.clear();
                navigate("/");
              }}
              className="w-full bg-red-500 text-white py-2 rounded-lg"
            >
              Logout
            </button>

          </div>
        </div>

        {/* RIGHT PANEL */}
        <div className="col-span-2 space-y-6">

          <div className="grid grid-cols-2 gap-4">

            <div className="bg-white p-4 rounded-xl shadow">
              Username: <b>{user.username}</b>
            </div>

            <div className="bg-white p-4 rounded-xl shadow">
              Role: <b>{user.role}</b>
            </div>

            <div className="bg-white p-4 rounded-xl shadow">
              Email Status: <b className="text-green-600">Verified</b>
            </div>

            <div className="bg-white p-4 rounded-xl shadow">
              Account Type:{" "}
              <b>
                {role === "admin" ? "System Admin" : "Academic Access"}
              </b>
            </div>

          </div>

        </div>
      </div>

      {/* MODAL */}
      {showEditProfile && (
        <EditProfile
          closeModal={() => setShowEditProfile(false)}
          onUpdate={fetchUser}
        />
      )}

    </div>
  );
}
